# Create a token lifetime policy for B2C — controls ID token, access token, and refresh token lifetimes
$tokenPolicy = @{
    Definition = @(
        '{"TokenLifetimePolicy":{"Version":1,"AccessTokenLifetime":"01:00:00","MaxAgeSessionSingleFactor":"7.00:00:00"}}'
    )
    DisplayName           = 'B2CTokenPolicy'
    IsOrganizationDefault = $true
}

New-MgPolicyTokenLifetimePolicy -BodyParameter $tokenPolicy
Write-Host 'Token lifetime policy created.'

# Register a web application in the B2C tenant
Connect-MgGraph -TenantId 'contoso.onmicrosoft.com' -Scopes 'Application.ReadWrite.All'

$app = New-MgApplication -BodyParameter @{
    DisplayName = 'Contoso Web App'
    SignInAudience = 'AzureADandPersonalMicrosoftAccount'
    Web = @{
        RedirectUris = @('https://contoso.com/auth/callback', 'https://localhost:5001/signin-oidc')
        ImplicitGrantSettings = @{
            EnableIdTokenIssuance     = $true
            EnableAccessTokenIssuance = $false
        }
    }
    RequiredResourceAccess = @(
        @{
            ResourceAppId = '00000003-0000-0000-c000-000000000000'  # Microsoft Graph
            ResourceAccess = @(
                @{ Id = 'e1fe6dd8-ba31-4d61-89e7-88639da4683d'; Type = 'Scope' }  # User.Read
            )
        }
    )
}

Write-Host "App registered: $($app.AppId)"

terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 3.80"
    }
  }
}

provider "azurerm" {
  features {}
}

resource "azurerm_resource_group" "b2c" {
  name     = "rg-b2c-prod"
  location = "East US"
}

resource "azurerm_aadb2c_directory" "contoso" {
  # The .onmicrosoft.com domain for the new B2C tenant
  domain_name             = "contosociam.onmicrosoft.com"
  resource_group_name     = azurerm_resource_group.b2c.name
  location                = "United States"
  display_name            = "Contoso CIAM"
  sku_name                = "PremiumP1"
  data_residency_location = "United States"
}

output "b2c_tenant_id" {
  value = azurerm_aadb2c_directory.contoso.tenant_id
}

output "b2c_tenant_domain" {
  value = azurerm_aadb2c_directory.contoso.domain_name
}

Connect-MgGraph -TenantId 'contosociam.onmicrosoft.com' `
    -Scopes 'TrustFrameworkKeySet.ReadWrite.All'

# List existing key sets
$keySets = Get-MgTrustFrameworkKeySet
foreach ($ks in $keySets) {
    Write-Host "KeySet: $($ks.Id)"
    foreach ($key in $ks.Keys) {
        Write-Host "  Kid=$($key.Kid) Use=$($key.Use) NBF=$($key.Nbf) Exp=$($key.Exp)"
    }
}

# Generate a new RSA signing key
New-MgTrustFrameworkKeySetKey `
    -TrustFrameworkKeySetId 'B2C_1A_TokenSigningKeyContainer' `
    -BodyParameter @{
        use = 'sig'
        kty = 'RSA'
    }
Write-Host 'New signing key generated. Old key remains valid until its exp claim.'
